const body = $input.item.json.body || {};
const plan = String(body.plan || '').trim();
const email = String(body.email || '').trim();
// plan -> { price env var name, product entitlement granted on payment }
const PLAN_MAP = {
  sentinel_starter: { env: 'STRIPE_PRICE_SENTINEL_STARTER', product: 'sentinel' },
  sentinel_growth:  { env: 'STRIPE_PRICE_SENTINEL_GROWTH',  product: 'sentinel' },
  sentinel_scale:   { env: 'STRIPE_PRICE_SENTINEL_SCALE',   product: 'sentinel' },
  consulting_founding_1997:        { env: 'STRIPE_PRICE_CONSULTING_FOUNDING_1997',        product: 'sales_engine' },
  real_estate_founding_1497:       { env: 'STRIPE_PRICE_REAL_ESTATE_FOUNDING_1497',       product: 'sales_engine' },
  construction_1497:               { env: 'STRIPE_PRICE_CONSTRUCTION_1497',               product: 'sales_engine' },
  dental_founding_1497:            { env: 'STRIPE_PRICE_DENTAL_FOUNDING_1497',            product: 'sales_engine' },
  insurance_broker_founding_1997:  { env: 'STRIPE_PRICE_INSURANCE_BROKER_FOUNDING_1997',  product: 'sales_engine' }
};
const m = PLAN_MAP[plan];
if (!m) return { json: { ok: false, status: 400, error: 'Unknown plan: ' + (plan || '(missing)') } };
return { json: { ok: true, plan: plan, email: email, price_env: m.env, product: m.product } };

const s = $input.item.json || {};
if (s.error) {
  const msg = s.error.message || s.error.type || 'Stripe error';
  // Most common: the STRIPE_PRICE_* env var isn't set yet.
  return { json: { ok: false, status: 400, error: msg.indexOf('price') !== -1 ? 'Pricing not configured yet for this plan (set the STRIPE_PRICE_* env var in n8n).' : ('Stripe: ' + msg) } };
}
if (!s.url) return { json: { ok: false, status: 400, error: 'Stripe did not return a checkout URL (is STRIPE_SECRET_KEY set?)' } };
return { json: { ok: true, status: 200, url: s.url, session_id: s.id } };
